package events

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type RealtimeProxy struct {
	events.UnimplementedRealtimeServer
	client events.RealtimeClient
}

func init() {
	proxyutil.Register(&events.Realtime_ServiceDesc, NewRealtimeProxy)
}
func NewRealtimeProxy(cc grpc.ClientConnInterface) events.RealtimeServer {
	return &RealtimeProxy{client: events.NewRealtimeClient(cc)}
}
func (p *RealtimeProxy) Send(ctx context.Context, in *events.RealtimeEvent) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[events.RealtimeEvent, emptypb.Empty](p.client.Send)(ctx, in)
}
